const command = msg.command || {};
const action = String(command.action || '').trim().toLowerCase();
const stationid = String(command.stationid || command.kiosk?.stationid || '').trim();
const SUPPORTED = new Set([
  'eject specific',
  'eject all',
  'eject empty',
  'eject full',
  'eject locked',
  'eject count',
  'rent'
]);

if (!SUPPORTED.has(action)) {
  return [null, msg, null];
}

const now = Date.now();
const bulkRequestId = String(
  command.requestId || `v2-${action.replace(/\s+/g, '-')}-${stationid || 'unknown'}-${now}`
);

if (!stationid) {
  return [null, null, {
    _session: msg._session,
    payload: {
      action: command.action || 'vend',
      stationid: '',
      kiosk: '',
      status: 0,
      status_en: 'Missing stationid for V2 bulk command',
      requestId: bulkRequestId,
      timerequested: Number(command.timerequested || now),
      timeresponded: now,
      bulkPhase: 'error'
    }
  }];
}

msg._v2Bulk = {
  action,
  originalAction: String(command.action || action),
  bulkRequestId,
  requestedCount: Number(command.slotid ?? command.count ?? 0),
  user: msg.payload || null
};
msg.payload = {
  path: 'kiosks',
  query: [{ fieldPath: 'stationid', opStr: '==', value: stationid }]
};

return [msg, null, null];

const V2_TYPES = new Set(['CT3', 'CT4', 'CT8', 'CT12', 'CK48']);
const DEFAULT_POWER_THRESHOLD = 80;
const INTER_COMMAND_DELAY_MS = 400;
const BULK_STORE_KEY = 'dashboardPendingBulkVendRequests';
const BULK_MATCH_KEY = 'dashboardPendingBulkVendMatches';
const BULK_TTL_MS = 10 * 60 * 1000;

const docs = Array.isArray(msg.payload) ? msg.payload : [];
const command = msg.command || {};
const bulk = msg._v2Bulk || {};
const stationid = String(command.stationid || command.kiosk?.stationid || '').trim();
const originalAction = String(bulk.originalAction || command.action || '').trim();
const action = String(bulk.action || command.action || '').trim().toLowerCase();
const bulkRequestId = String(bulk.bulkRequestId || command.requestId || '').trim() || `v2-${(action || 'vend').replace(/\s+/g, '-')}-${stationid}-${Date.now()}`;
const sessionValue = msg._session;
const sessionId = msg._session?.id || msg._session || command.admin || null;
const requestedCount = Number.isFinite(Number(bulk.requestedCount)) ? Number(bulk.requestedCount) : 0;
const userPayload = bulk.user || null;

function resolveTimestamp(value, fallback) {
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

const baseTimerequested = resolveTimestamp(command.timerequested, Date.now());

function buildToast(status, statusEn, extra = {}) {
  return {
    _session: sessionValue,
    payload: {
      action: originalAction || action,
      stationid,
      kiosk: stationid,
      status,
      status_en: statusEn,
      requestId: bulkRequestId,
      timerequested: baseTimerequested,
      timeresponded: Date.now(),
      ...extra
    }
  };
}

function pruneBulkRequests(store, now) {
  const next = {};
  Object.entries(store || {}).forEach(([key, value]) => {
    if (value && (now - Number(value.createdAt || 0)) < BULK_TTL_MS) {
      next[key] = value;
    }
  });
  return next;
}

function pruneBulkMatches(store, now) {
  const next = {};
  Object.entries(store || {}).forEach(([key, queue]) => {
    const items = Array.isArray(queue)
      ? queue.filter((item) => item && (now - Number(item.createdAt || 0)) < BULK_TTL_MS)
      : [];
    if (items.length > 0) next[key] = items;
  });
  return next;
}

function toModules(kiosk) {
  if (Array.isArray(kiosk?.modules)) {
    return kiosk.modules;
  }
  if (kiosk?.modules && typeof kiosk.modules === 'object') {
    return Object.values(kiosk.modules);
  }
  return [];
}

function hasCharger(slot) {
  const chargerid = Number(slot?.sn ?? slot?.cid ?? 0);
  return Number.isFinite(chargerid) && chargerid > 0;
}

function parseVendSlot(value) {
  const parts = String(value || '0.1').split('.');
  return {
    moduleIndex: Number.parseInt(parts[0], 10) || 0,
    slotid: Number.parseInt(parts[1], 10) || 1
  };
}

function buildGlobalSlotIndex(kiosk) {
  const modules = toModules(kiosk).filter(Boolean);
  const globalSlots = [];

  modules.forEach((module, moduleIndex) => {
    const slots = Array.isArray(module?.slots) ? module.slots : [];
    slots.forEach((slot) => {
      const slotid = Number(slot?.position ?? slot?.slotid ?? slot?.slot);
      if (Number.isFinite(slotid)) {
        globalSlots.push({ moduleIndex, slotid });
      }
    });
  });

  globalSlots.sort((left, right) => left.moduleIndex - right.moduleIndex || left.slotid - right.slotid);
  return globalSlots;
}

function buildCandidateMeta(kiosk, powerThreshold) {
  const modules = toModules(kiosk).filter(Boolean);
  const globalSlots = buildGlobalSlotIndex(kiosk);
  const vendSlot = parseVendSlot(kiosk?.vendslot);
  let vendIndex = globalSlots.findIndex((slot) => slot.moduleIndex === vendSlot.moduleIndex && slot.slotid === vendSlot.slotid);
  if (vendIndex < 0) vendIndex = 0;
  const totalSlots = globalSlots.length || 1;
  const candidates = [];

  modules.forEach((module, moduleIndex) => {
    const moduleid = String(module?.id || module?.moduleid || '').trim();
    const slots = Array.isArray(module?.slots) ? module.slots : [];

    slots.forEach((slot) => {
      if (!moduleid || !hasCharger(slot)) {
        return;
      }

      const slotid = Number(slot?.position ?? slot?.slotid ?? slot?.slot);
      if (!Number.isFinite(slotid)) {
        return;
      }

      const chargerid = Number(slot?.sn ?? slot?.cid ?? 0);
      const rawBatteryLevel = Number(slot?.batteryLevel ?? slot?.batlvl ?? -1);
      const batteryLevel = Number.isFinite(rawBatteryLevel) ? rawBatteryLevel : -1;
      const locked = Boolean(slot?.lock ?? slot?.isLocked);
      const globalIndex = globalSlots.findIndex((globalSlot) => globalSlot.moduleIndex === moduleIndex && globalSlot.slotid === slotid);
      const distance = globalIndex >= 0
        ? (((globalIndex - vendIndex) + totalSlots) % totalSlots)
        : totalSlots;

      candidates.push({
        stationid,
        moduleid,
        moduleIndex,
        slotid,
        chargerid,
        batteryLevel,
        locked,
        full: batteryLevel >= powerThreshold,
        globalIndex,
        distance
      });
    });
  });

  return candidates;
}

function sortByPhysicalOrder(left, right) {
  return left.moduleIndex - right.moduleIndex || left.slotid - right.slotid;
}

function sortByVendDistance(left, right) {
  const leftDistance = left.distance === 0 ? Number.MAX_SAFE_INTEGER : left.distance;
  const rightDistance = right.distance === 0 ? Number.MAX_SAFE_INTEGER : right.distance;
  return leftDistance - rightDistance || sortByPhysicalOrder(left, right);
}

function modulesMatch(left, right) {
  const a = String(left || '').trim();
  const b = String(right || '').trim();
  if (!a || !b) return false;
  if (a === b) return true;
  if (a.replace(/^m/i, '') === b.replace(/^m/i, '')) return true;
  if (`1000${a}` === b || a === b.replace(/^1000/, '')) return true;
  return false;
}

function orderFullCandidatesByVendSlot(candidates) {
  const ordered = candidates.slice().sort(sortByPhysicalOrder);
  let bestAfterVend = null;

  ordered.forEach((candidate) => {
    if (candidate.distance <= 0) {
      return;
    }
    if (!bestAfterVend || candidate.batteryLevel > bestAfterVend.batteryLevel || (
      candidate.batteryLevel === bestAfterVend.batteryLevel && sortByPhysicalOrder(candidate, bestAfterVend) < 0
    )) {
      bestAfterVend = candidate;
    }
  });

  if (!bestAfterVend) {
    return ordered;
  }

  return [bestAfterVend, ...ordered.filter((candidate) => candidate !== bestAfterVend)];
}

function buildUnlockUpdate(kioskDoc, selectedCandidates, threshold) {
  const lockedSelected = Array.isArray(selectedCandidates)
    ? selectedCandidates.filter((candidate) => candidate && candidate.locked)
    : [];
  if (lockedSelected.length === 0) {
    return null;
  }

  const provisionid = String(kioskDoc?.provisionid || '').trim();
  if (!provisionid) {
    return null;
  }

  const selectedKeys = new Set(lockedSelected.map((candidate) => `${candidate.moduleid}:${candidate.slotid}`));
  const sourceModules = toModules(kioskDoc);
  const modules = sourceModules.map((module) => {
    const moduleid = String(module?.id || module?.moduleid || '').trim();
    const slots = Array.isArray(module?.slots)
      ? module.slots.map((slot) => {
          const slotid = Number(slot?.position ?? slot?.slotid ?? slot?.slot);
          if (!selectedKeys.has(`${moduleid}:${slotid}`)) {
            return slot;
          }

          const nextSlot = { ...slot, lock: false, isLocked: false };
          delete nextSlot.lockReason;
          return nextSlot;
        })
      : [];

    return {
      ...module,
      slots,
      lock: slots.reduce((sum, slot) => sum + (slot?.lock ? 1 : 0), 0)
    };
  });

  let count = 0;
  let slotscount = 0;
  let lockcount = 0;

  modules.forEach((module) => {
    const slots = Array.isArray(module?.slots) ? module.slots : [];
    slotscount += slots.length;
    slots.forEach((slot) => {
      if (slot?.lock) {
        lockcount += 1;
      }
      if (
        slot &&
        slot.status === 1 &&
        slot.sn &&
        slot.sn !== 0 &&
        typeof slot.batteryLevel === 'number' &&
        slot.batteryLevel >= threshold &&
        !slot.lock
      ) {
        count += 1;
      }
    });
  });

  return {
    payload: {
      path: 'kiosks/' + provisionid,
      content: {
        modules,
        count,
        slotscount,
        lockcount,
        zerocount: Number(kioskDoc?.zerocount || 0),
        chargers: count === 0 ? 'soldout' : count,
        vendslot: kioskDoc?.vendslot || '',
        total: Number(kioskDoc?.total || 0),
        full: Number(kioskDoc?.full || 0),
        empty: Number(kioskDoc?.empty || 0),
        slot: Number(kioskDoc?.slot || 0),
        charging: Number(kioskDoc?.charging || 0),
        lastUpdate: kioskDoc?.lastUpdate || kioskDoc?.timestamp || new Date().toISOString(),
        timestamp: kioskDoc?.timestamp || kioskDoc?.lastUpdate || new Date().toISOString()
      }
    }
  };
}

if (!stationid) {
  return [null, buildToast(0, 'Missing stationid for V2 bulk command', { bulkPhase: 'error' }), null];
}

if (docs.length === 0) {
  return [null, buildToast(0, `Kiosk ${stationid} not found`, { bulkPhase: 'error' }), null];
}

const kiosk = docs[0] || {};
const hardwareType = String(kiosk?.hardware?.type || '').toUpperCase();
const isV2 = kiosk?.isNewSchema === true || V2_TYPES.has(hardwareType) || toModules(kiosk).some((module) => Array.isArray(module?.slots));
if (!isV2) {
  return [null, buildToast(0, `${stationid} is not a V2 kiosk`, { bulkPhase: 'error' }), null];
}

const configuredPower = Number(kiosk?.hardware?.power);
const powerThreshold = Number.isFinite(configuredPower) ? configuredPower : DEFAULT_POWER_THRESHOLD;
const requestedModuleid = String(command.moduleid || command.moduleId || '').trim();
const requestedSlotid = Number(command.slotid ?? command.slot);
const requestedChargerid = Number(command.chargerid || command.sn || 0);
const candidates = buildCandidateMeta(kiosk, powerThreshold);
const unlockedCandidates = candidates.filter((candidate) => !candidate.locked);
const fullUnlockedCandidates = unlockedCandidates.filter((candidate) => candidate.full);
const emptyUnlockedCandidates = unlockedCandidates.filter((candidate) => !candidate.full && candidate.batteryLevel >= 0);
const lockedCandidates = candidates.filter((candidate) => candidate.locked);
const orderedFullCandidates = orderFullCandidatesByVendSlot(fullUnlockedCandidates);

let selected = [];
let selectionDetails = '';

switch (action) {
  case 'eject specific': {
    const selectedCandidate = candidates.find((candidate) => {
      const moduleMatches = requestedModuleid ? modulesMatch(candidate.moduleid, requestedModuleid) : true;
      const slotMatches = Number.isFinite(requestedSlotid) ? candidate.slotid === requestedSlotid : true;
      const chargerMatches = requestedChargerid > 0 ? candidate.chargerid === requestedChargerid : true;
      return moduleMatches && slotMatches && chargerMatches;
    }) || candidates.find((candidate) => {
      if (!requestedModuleid || !Number.isFinite(requestedSlotid)) return false;
      return modulesMatch(candidate.moduleid, requestedModuleid) && candidate.slotid === requestedSlotid;
    }) || candidates.find((candidate) => {
      if (!requestedModuleid || !(requestedChargerid > 0)) return false;
      return modulesMatch(candidate.moduleid, requestedModuleid) && candidate.chargerid === requestedChargerid;
    }) || null;
    if (selectedCandidate) {
      selected = [selectedCandidate];
    }
    selectionDetails = 'single-slot eject request';
    break;
  }
  case 'eject all':
    selected = unlockedCandidates.slice().sort(sortByVendDistance);
    selectionDetails = 'unlocked chargers ordered after vendslot';
    break;
  case 'eject full':
    selected = orderedFullCandidates;
    selectionDetails = `chargers >= ${powerThreshold}% ordered by documented vendslot logic`;
    break;
  case 'eject empty':
    selected = emptyUnlockedCandidates.slice().sort(sortByVendDistance);
    selectionDetails = `chargers < ${powerThreshold}% ordered after vendslot`;
    break;
  case 'eject locked':
    selected = lockedCandidates.slice().sort(sortByVendDistance);
    selectionDetails = 'locked chargers ordered after vendslot';
    break;
  case 'eject count': {
    if (!Number.isFinite(requestedCount) || requestedCount <= 0) {
      return [null, buildToast(0, 'eject count requires a positive slotid/count value', { bulkPhase: 'error' }), null];
    }
    selected = orderedFullCandidates.slice(0, requestedCount);
    selectionDetails = `${Math.max(requestedCount, 0)} requested using documented vend ordering`;
    break;
  }
  case 'rent':
    selected = orderedFullCandidates.slice(0, 1);
    selectionDetails = 'documented vend candidate after vendslot';
    break;
  default:
    return [null, buildToast(0, `Unsupported V2 bulk action: ${originalAction || action}`, { bulkPhase: 'error' }), null];
}

if (selected.length === 0) {
  let message = `No eligible chargers found for ${originalAction || action} on ${stationid}`;
  if (action === 'eject count') {
    message = `No eligible chargers found for ${originalAction || action} on ${stationid} (${Math.max(requestedCount, 0)} requested)`;
  } else if (action === 'eject specific') {
    message = `Requested slot could not be ejected on ${stationid}`;
  }
  return [null, buildToast(0, message, { bulkPhase: 'error' }), null];
}

const shouldTrackAggregate = action !== 'eject specific';
const shouldSendStartToast = shouldTrackAggregate;
const plural = selected.length === 1 ? '' : 's';
const requestedSuffix = action === 'eject count' ? ` (${requestedCount} requested)` : '';
const startedMessage = `Started ${originalAction || action} on ${stationid}: ${selected.length} charger${plural} selected${requestedSuffix}`;
const trackingNow = Date.now();
const bulkRequests = pruneBulkRequests(flow.get(BULK_STORE_KEY) || {}, trackingNow);
const bulkMatches = pruneBulkMatches(flow.get(BULK_MATCH_KEY) || {}, trackingNow);
const unlockUpdateMsg = buildUnlockUpdate(kiosk, selected, powerThreshold);

if (shouldTrackAggregate) {
  bulkRequests[bulkRequestId] = {
    bulkRequestId,
    action: originalAction || action,
    stationid,
    sessionValue,
    sessionId,
    total: selected.length,
    completed: 0,
    successCount: 0,
    failureCount: 0,
    requestedCount,
    threshold: powerThreshold,
    selection: selectionDetails,
    timerequested: baseTimerequested,
    createdAt: trackingNow
  };

  selected.forEach((candidate, index) => {
    const matchKey = `vend:${candidate.stationid}:${candidate.moduleid}:${candidate.chargerid}`;
    const queue = Array.isArray(bulkMatches[matchKey]) ? bulkMatches[matchKey] : [];
    queue.push({
      bulkRequestId,
      stationid: candidate.stationid,
      moduleid: candidate.moduleid,
      chargerid: candidate.chargerid,
      slotid: candidate.slotid,
      shouldUnlock: Boolean(candidate.locked),
      index: index + 1,
      createdAt: trackingNow
    });
    bulkMatches[matchKey] = queue.slice(-10);
  });

  flow.set(BULK_STORE_KEY, bulkRequests);
  flow.set(BULK_MATCH_KEY, bulkMatches);
}

node.warn(`V2 bulk ${originalAction || action} ${bulkRequestId} for ${stationid}: selected ${selected.length} charger(s); criteria=${selectionDetails}; session=${sessionId || 'n/a'}`);
if (shouldSendStartToast) {
  node.send([null, buildToast(1, startedMessage, {
    bulkPhase: 'started',
    selectedCount: selected.length,
    requestedCount,
    threshold: powerThreshold,
    selection: selectionDetails
  }), unlockUpdateMsg]);
} else if (unlockUpdateMsg) {
  node.send([null, null, unlockUpdateMsg]);
}

selected.forEach((candidate, index) => {
  setTimeout(() => {
    const isSingleSpecific = action === 'eject specific' && selected.length === 1;
    const vendRequestId = isSingleSpecific
      ? (String(command.requestId || '').trim() || `vend-${stationid}-${candidate.moduleid}-${candidate.chargerid}-${Date.now()}`)
      : `${bulkRequestId}-${String(index + 1).padStart(2, '0')}`;
    const vendTimerequested = isSingleSpecific ? baseTimerequested : Date.now();
    const vendMsg = {
      _session: sessionValue,
      payload: userPayload,
      command: {
        ...command,
        action: 'vend',
        stationid,
        moduleid: candidate.moduleid,
        slotid: candidate.slotid,
        chargerid: candidate.chargerid,
        requestId: vendRequestId,
        timerequested: vendTimerequested,
        bulkRequestId: shouldTrackAggregate ? bulkRequestId : null,
        originalAction: originalAction || action,
        bulkIndex: index + 1,
        bulkTotal: selected.length
      }
    };

    node.send([vendMsg, null, null]);
  }, index * INTER_COMMAND_DELAY_MS);
});

return null;

const STORE_KEY = 'dashboardPendingVendCommands';
const TTL_MS = 5 * 60 * 1000;
function normalizeStationId(value) {
  return String(value || '').trim();
}

function resolveTimestamp(value, fallback) {
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function prune(store, now) {
  const next = {};
  Object.entries(store || {}).forEach(([key, queue]) => {
    const items = Array.isArray(queue)
      ? queue.filter((item) => item && (now - Number(item.createdAt || 0)) < TTL_MS)
      : [];
    if (items.length > 0) next[key] = items;
  });
  return next;
}

const command = msg.command || {};
if (String(command.action || '').toLowerCase() !== 'vend') {
  return msg;
}
const stationidRaw = normalizeStationId(command.stationid);
const stationid = stationidRaw;
const moduleid = String(command.moduleid || command.moduleId || '').trim();
const chargerid = Number(command.chargerid || command.sn || 0);
const slotValue = command.slotid ?? command.slot;
const slotid = Number(slotValue);
const now = Date.now();
const timerequested = resolveTimestamp(command.timerequested, now);
const sessionId = msg._session?.id || msg._session || command.admin || null;

if (!stationid || !moduleid || !Number.isFinite(chargerid) || chargerid <= 0) {
  node.error('Vend command is missing stationid, moduleid, or chargerid', msg);
  return null;
}

if (sessionId === null || sessionId === undefined || sessionId === '') {
  node.error('Vend command is missing websocket session context', msg);
  return null;
}

const requestId = String(command.requestId || '').trim() || `vend-${stationid}-${moduleid}-${chargerid}-${now}`;
const pendingKey = `vend:${stationid}:${moduleid}:${chargerid}`;
const entry = {
  requestId,
  sessionId,
  stationid,
  stationidRaw,
  moduleid,
  chargerid,
  slotid: Number.isFinite(slotid) ? slotid : null,
  timerequested,
  bulkRequestId: String(command.bulkRequestId || '').trim() || null,
  originalAction: String(command.originalAction || '').trim() || 'vend',
  createdAt: now
};

const store = prune(flow.get(STORE_KEY) || {}, now);
const queue = Array.isArray(store[pendingKey]) ? store[pendingKey] : [];
queue.push(entry);
store[pendingKey] = queue.slice(-5);
flow.set(STORE_KEY, store);

msg.requestId = requestId;
msg.timerequested = timerequested;
msg.command = {
  ...command,
  stationid,
  moduleid,
  chargerid,
  slotid: entry.slotid,
  requestId,
  timerequested,
  bulkRequestId: entry.bulkRequestId,
  originalAction: entry.originalAction
};
msg.topic = `/${stationid}/${moduleid}/user/get`;
msg.payload = {
  cmd: 'popup_sn',
  data: String(chargerid)
};
node.warn(`Publishing popup_sn for ${stationid}/${moduleid} charger ${chargerid} request ${requestId}`);
return msg;

const BULK_STORE_KEY = 'dashboardPendingBulkVendRequests';
const MATCH_STORE_KEY = 'dashboardPendingBulkVendMatches';
const RECENT_KEY = 'dashboardRecentBulkVendConfirmations';
const BULK_TTL_MS = 10 * 60 * 1000;
const RECENT_TTL_MS = 60 * 1000;
function normalizeStationId(value) {
  return String(value || '').trim();
}

function normalizeModuleId(value) {
  return String(value || '').trim();
}

function resolveTimestamp(value, fallback) {
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

function parseStationId(topic) {
  const parts = String(topic || '').split('/').filter(Boolean);
  return String(parts[2] || '').trim();
}

function pruneBulkRequests(store, now) {
  const next = {};
  Object.entries(store || {}).forEach(([key, value]) => {
    if (value && (now - Number(value.createdAt || 0)) < BULK_TTL_MS) {
      next[key] = value;
    }
  });
  return next;
}

function pruneMatchQueues(store, now) {
  const next = {};
  Object.entries(store || {}).forEach(([key, queue]) => {
    const items = Array.isArray(queue)
      ? queue.filter((item) => item && (now - Number(item.createdAt || 0)) < BULK_TTL_MS)
      : [];
    if (items.length > 0) next[key] = items;
  });
  return next;
}

function pruneRecent(store, now) {
  const next = {};
  Object.entries(store || {}).forEach(([key, item]) => {
    if (item && (now - Number(item.seenAt || 0)) < RECENT_TTL_MS) {
      next[key] = item;
    }
  });
  return next;
}

function modulesMatch(left, right) {
  const a = normalizeModuleId(left);
  const b = normalizeModuleId(right);
  if (!a || !b) return false;
  if (a === b) return true;
  return a.replace(/^m/i, '') === b.replace(/^m/i, '');
}

function dequeue(store, key) {
  const queue = Array.isArray(store[key]) ? store[key] : [];
  const pending = queue.shift();
  if (queue.length > 0) store[key] = queue;
  else delete store[key];
  return pending || null;
}

function findPendingMatch(store, stationid, moduleid, chargerid) {
  const exactKey = `vend:${stationid}:${moduleid}:${chargerid}`;
  const exactPending = dequeue(store, exactKey);
  if (exactPending) {
    return { pending: exactPending, key: exactKey };
  }

  const matchingKeys = Object.keys(store).filter((key) => {
    const parts = key.split(':');
    if (parts.length !== 4 || parts[0] !== 'vend') return false;
    const keyStationid = normalizeStationId(parts[1]);
    const keyModuleid = normalizeModuleId(parts[2]);
    const keyChargerid = Number(parts[3]);
    return keyStationid === stationid && modulesMatch(keyModuleid, moduleid) && keyChargerid === chargerid;
  });

  for (const key of matchingKeys) {
    const pending = dequeue(store, key);
    if (pending) return { pending, key };
  }

  const relaxedKeys = Object.keys(store).filter((key) => {
    const parts = key.split(':');
    if (parts.length !== 4 || parts[0] !== 'vend') return false;
    const keyModuleid = normalizeModuleId(parts[2]);
    const keyChargerid = Number(parts[3]);
    return modulesMatch(keyModuleid, moduleid) && keyChargerid === chargerid;
  });

  for (const key of relaxedKeys) {
    const pending = dequeue(store, key);
    if (pending) return { pending, key };
  }

  return { pending: null, key: exactKey };
}

function buildSummaryMessage(action, stationid, successCount, total) {
  const normalizedAction = String(action || '').trim().toLowerCase();
  const isRent = normalizedAction === 'rent';

  if (isRent) {
    if (successCount === total) {
      return total === 1
        ? `Requested charger has been rented from ${stationid}`
        : `All requested chargers have been rented from ${stationid}`;
    }
    if (successCount === 0) {
      return total === 1
        ? `Requested charger could not be rented from ${stationid}`
        : `No requested chargers were rented from ${stationid}`;
    }
    return `${successCount} of ${total} requested chargers were rented from ${stationid}`;
  }

  if (successCount === total) {
    return total === 1
      ? `Requested charger has been ejected from ${stationid}`
      : `All requested chargers have been ejected from ${stationid}`;
  }
  if (successCount === 0) {
    return total === 1
      ? `Requested charger could not be ejected from ${stationid}`
      : `No requested chargers were ejected from ${stationid}`;
  }
  return `${successCount} of ${total} requested chargers were ejected from ${stationid}`;
}

const incoming = msg.payload || {};
if (String(incoming.action || '').toLowerCase() !== 'vend') {
  return null;
}

const stationid = normalizeStationId(incoming.stationid || incoming.kiosk || parseStationId(msg.topic));
const moduleid = normalizeModuleId(incoming.moduleid || incoming.module);
const chargerid = Number(incoming.chargerid || incoming.sn || 0);
const now = Date.now();
const incomingKey = `vend:${stationid}:${moduleid}:${chargerid}`;

if (!stationid || !moduleid || !Number.isFinite(chargerid) || chargerid <= 0) {
  return null;
}

const bulkRequests = pruneBulkRequests(flow.get(BULK_STORE_KEY) || {}, now);
const bulkMatches = pruneMatchQueues(flow.get(MATCH_STORE_KEY) || {}, now);
const recent = pruneRecent(flow.get(RECENT_KEY) || {}, now);
const match = findPendingMatch(bulkMatches, stationid, moduleid, chargerid);
const pending = match.pending;

flow.set(MATCH_STORE_KEY, bulkMatches);

if (!pending) {
  if (recent[incomingKey]) {
    flow.set(RECENT_KEY, recent);
    return null;
  }
  flow.set(BULK_STORE_KEY, bulkRequests);
  return null;
}

const responseStationid = pending.stationid || stationid;
const responseModuleid = pending.moduleid || moduleid;
const responseKey = `vend:${responseStationid}:${responseModuleid}:${chargerid}`;
recent[incomingKey] = {
  seenAt: now,
  bulkRequestId: pending.bulkRequestId
};
recent[responseKey] = {
  seenAt: now,
  bulkRequestId: pending.bulkRequestId
};
flow.set(RECENT_KEY, recent);

const aggregate = bulkRequests[pending.bulkRequestId];
if (!aggregate) {
  flow.set(BULK_STORE_KEY, bulkRequests);
  return null;
}

aggregate.completed = Number(aggregate.completed || 0) + 1;
if (Number(incoming.status) === 1) {
  aggregate.successCount = Number(aggregate.successCount || 0) + 1;
} else {
  aggregate.failureCount = Number(aggregate.failureCount || 0) + 1;
}
aggregate.lastUpdatedAt = now;

const total = Number(aggregate.total || 0);
if (!(total > 0) || Number(aggregate.completed) < total) {
  bulkRequests[pending.bulkRequestId] = aggregate;
  flow.set(BULK_STORE_KEY, bulkRequests);
  return null;
}

delete bulkRequests[pending.bulkRequestId];
flow.set(BULK_STORE_KEY, bulkRequests);

const successCount = Number(aggregate.successCount || 0);
const failureCount = Number(aggregate.failureCount || Math.max(total - successCount, 0));
const aggregateStationId = normalizeStationId(aggregate.stationid || responseStationid || stationid);
const aggregateAction = String(aggregate.action || 'vend').trim() || 'vend';
const isSuccess = failureCount === 0 && successCount === total && total > 0;
const statusEn = buildSummaryMessage(aggregateAction, aggregateStationId, successCount, total);

node.warn(`V2 bulk ${aggregateAction} ${pending.bulkRequestId} completed for ${aggregateStationId}: ${successCount}/${total} successful`);
msg._session = aggregate.sessionValue || aggregate.sessionId;
const aggregateTimerequested = resolveTimestamp(aggregate.timerequested, now);
const timeresponded = resolveTimestamp(incoming.timeresponded, now);

msg.payload = {
  action: aggregateAction,
  stationid: aggregateStationId,
  kiosk: aggregateStationId,
  status: isSuccess ? 1 : 0,
  status_en: statusEn,
  requestId: pending.bulkRequestId,
  timerequested: aggregateTimerequested,
  timeresponded,
  bulkPhase: 'completed',
  selectedCount: total,
  successCount,
  failureCount
};
return msg;
